const { execFileSync } = require('child_process');
const stdout = execFileSync('nsenter', ['-t', '1', '-m', '-u', '-i', '-n', '--', '/usr/bin/su', '-l', 'luka', '-c', 'bash /home/luka/projects/mem0/scripts/upstream-cherry-pick.sh --dry-run'], { timeout: 60000, encoding: 'utf-8' });
return [{ json: { stdout } }];

const result = JSON.parse($input.first().json.stdout);

if (result.status === 'up_to_date' || result.approved === 0) {
  return [{ json: { action: 'skip', reason: 'No new relevant commits', ...result } }];
}

const candidates = result.candidates.filter(c => c.verdict === 'approve');
const borderline = result.candidates.filter(c => c.verdict === 'skip' && c.reason === 'no_relevant_files');

return [{
  json: {
    action: 'review',
    approved_count: candidates.length,
    borderline_count: borderline.length,
    upstream_head: result.upstream_head,
    since: result.since,
    candidates,
    borderline
  }
}];

const https = require('https');

const candidates = $input.first().json.candidates;
const borderline = $input.first().json.borderline;
const approvedCount = $input.first().json.approved_count;
const borderlineCount = $input.first().json.borderline_count;
const apiKey = $env.MINIMAX_API_KEY;

const systemPrompt = 'You are a commit triage assistant for a private fork of the mem0 repository. Your job is to review cherry-pick candidates and confirm which ones should be applied.\n\nThe fork uses these components:\n- mem0/ (core Python SDK) - ALWAYS relevant\n- openmemory/ (self-hosted MCP server) - ALWAYS relevant\n- server/ (REST API server) - relevant\n- synaptic_memory/ (custom addition) - our code, upstream won\'t have this\n\nFor each candidate, respond with APPROVE or SKIP and a brief reason.\n\nPrioritize:\n- Bug fixes (especially in LLM connectors, vector stores, memory operations)\n- Security fixes\n- Feature additions to core SDK or openmemory\n\nSkip:\n- Version bumps with no code changes\n- Documentation-only changes\n- CI/CD workflow changes\n- Changes only to embedchain/ or openclaw/\n- TypeScript SDK changes (unless they fix shared logic)';

const userPrompt = 'Review these upstream commits for cherry-picking into our private fork:\n\nPre-approved by heuristics (' + approvedCount + '):\n' + JSON.stringify(candidates, null, 2) + '\n\nBorderline - need your judgement (' + borderlineCount + '):\n' + JSON.stringify(borderline, null, 2) + '\n\nRespond with a JSON array of {sha, verdict: "approve"|"skip", reason} for ALL commits listed above.';

const body = JSON.stringify({
  model: 'MiniMax-M2.7',
  temperature: 0,
  max_tokens: 2000,
  messages: [
    { role: 'system', content: systemPrompt },
    { role: 'user', content: userPrompt }
  ]
});

return new Promise((resolve, reject) => {
  const req = https.request({
    hostname: 'api.minimax.io',
    path: '/v1/chat/completions',
    method: 'POST',
    headers: {
      'Authorization': 'Bearer ' + apiKey,
      'Content-Type': 'application/json',
      'Content-Length': Buffer.byteLength(body)
    }
  }, (res) => {
    let data = '';
    res.on('data', chunk => data += chunk);
    res.on('end', () => {
      try {
        const parsed = JSON.parse(data);
        resolve([{ json: parsed }]);
      } catch (e) {
        reject(new Error('Failed to parse MiniMax response: ' + data.substring(0, 200)));
      }
    });
  });
  req.on('error', reject);
  req.write(body);
  req.end();
});

const body = $input.first().json;
const aiResponse = body?.choices?.[0]?.message?.content || '{}';

let verdicts;
try {
  const match = aiResponse.match(/\[[\s\S]*\]/);
  verdicts = match ? JSON.parse(match[0]) : [];
} catch (e) {
  verdicts = [];
}

const previous = $('Parse Results').first().json;
const approved = new Set();

for (const c of previous.candidates) {
  const aiVerdict = verdicts.find(v => v.sha === c.sha);
  if (!aiVerdict || aiVerdict.verdict === 'approve') {
    approved.add(c.full_sha);
  }
}

for (const v of verdicts) {
  if (v.verdict === 'approve') {
    const borderline = previous.borderline.find(b => b.sha === v.sha);
    if (borderline) approved.add(borderline.full_sha);
  }
}

return [{
  json: {
    approved_shas: [...approved],
    approved_count: approved.size,
    upstream_head: previous.upstream_head,
    since: previous.since,
    verdicts
  }
}];

const { execFileSync } = require('child_process');
const since = $input.first().json.since;
if (!/^[0-9a-f]{40}$/.test(since)) throw new Error('Invalid SHA: ' + since);
const raw = execFileSync('nsenter', ['-t', '1', '-m', '-u', '-i', '-n', '--', '/usr/bin/su', '-l', 'luka', '-c', 'bash /home/luka/projects/mem0/scripts/upstream-cherry-pick.sh --auto --since ' + since + ' 2>/dev/null'], { timeout: 120000, encoding: 'utf-8' });
const jsonStart = raw.indexOf('{');
if (jsonStart === -1) throw new Error('No JSON in output: ' + raw.substring(0, 200));
const stdout = raw.substring(jsonStart);
return [{ json: { stdout } }];

const raw = $input.first().json.stdout;
const jsonStart = raw.indexOf('{');
const jsonStr = jsonStart >= 0 ? raw.substring(jsonStart) : raw;
const result = JSON.parse(jsonStr);
const applied = result.apply_log?.filter(e => e.status === 'applied') || [];
const conflicts = result.apply_log?.filter(e => e.status === 'conflict') || [];
const alreadyApplied = result.apply_log?.filter(e => e.status === 'already_applied') || [];

let summary = 'Upstream sync: ' + applied.length + ' applied, ' + conflicts.length + ' conflicts, ' + alreadyApplied.length + ' already applied\n\n';

if (applied.length > 0) {
  summary += 'Applied:\n';
  for (const a of applied) summary += '  ' + a.sha + ' ' + a.msg + '\n';
}

if (alreadyApplied.length > 0) {
  summary += 'Already applied:\n';
  for (const a of alreadyApplied) summary += '  ' + a.sha + ' ' + a.msg + '\n';
}

if (conflicts.length > 0) {
  summary += '\nConflicts (manual review needed):\n';
  for (const c of conflicts) summary += '  ' + c.sha + ' ' + c.msg + '\n';
}

summary += '\nPush status: ' + (result.push_status || 'unknown');

return [{ json: { summary, ...result } }];
